import { useEffect, useState, useRef } from "react";
import api from "../api";
import Badge from "../components/Badge";
import { useReactToPrint } from "react-to-print"; // ✅ updated import

export default function YouthList() {
  const [youth, setYouth] = useState([]);
  const [selectedYouth, setSelectedYouth] = useState(null);
  const [adminKey, setAdminKey] = useState("");

  const badgeRef = useRef();

  const handlePrint = useReactToPrint({
    content: () => badgeRef.current,
  });

  useEffect(() => {
    const key = prompt("Enter admin secret key:");
    if (!key) {
      alert("Admin key required");
      return;
    }

    setAdminKey(key);
    fetchYouth(key);
  }, []);

  const fetchYouth = async (key) => {
    try {
      const res = await api.get("/", {
        headers: { "x-admin-key": key },
      });

      setYouth(res.data);
    } catch {
      alert("Invalid admin key");
    }
  };

  const checkIn = async (id) => {
    try {
      await api.patch(`/${id}/checkin`, null, {
        headers: { "x-admin-key": adminKey },
      });

      fetchYouth(adminKey);
    } catch {
      alert("Check-in failed");
    }
  };

  const deleteYouth = async (id) => {
    if (!window.confirm("Delete this youth?")) return;

    try {
      await api.delete(`/${id}`, {
        headers: { "x-admin-key": adminKey },
      });

      fetchYouth(adminKey);
    } catch {
      alert("Delete failed");
    }
  };

  return (
    <div style={{ padding: "30px" }}>
      <h2>Youth List (Admin)</h2>

      {youth.map((y) => (
        <div
          key={y._id}
          style={{
            border: "1px solid #ddd",
            padding: "15px",
            marginBottom: "15px",
            borderRadius: "8px",
          }}
        >
          <strong>{y.fullName}</strong> — {y.congregation}

          <div style={{ marginTop: "10px" }}>
            {!y.checkedIn ? (
              <button onClick={() => checkIn(y._id)}>Check In</button>
            ) : (
              <span style={{ color: "green" }}>Checked In</span>
            )}

            <button
              onClick={() => deleteYouth(y._id)}
              style={{ marginLeft: "10px", color: "red" }}
            >
              Delete
            </button>

            <button
              style={{ marginLeft: "10px" }}
              onClick={() => setSelectedYouth(y)}
            >
              Prepare Badge
            </button>
          </div>
        </div>
      ))}

      {selectedYouth && (
        <div style={{ marginTop: "40px" }}>
          <Badge ref={badgeRef} youth={selectedYouth} />
          <button style={{ marginTop: "15px" }} onClick={handlePrint}>
            Print Badge
          </button>
        </div>
      )}
    </div>
  );
}
